    : 'bg-white text-primary hover:bg-gray-100';

  return (
    <nav className={navClasses}>
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between items-center">
          <div className="flex items-center">
            <span className={`text-2xl font-bold tracking-tighter ${textClasses}`}>Orderpin</span>
          </div>

          <div className="hidden md:flex items-center space-x-8">
            <button onClick={() => document.getElementById('pricing')?.scrollIntoView({behavior: 'smooth'})} className={`text-sm font-medium hover:text-secondary transition-colors ${textClasses}`}>
