            <button className={`text-sm font-medium hover:text-secondary transition-colors ${textClasses}`}>
              成功案例
            </button>
            <button className={`text-sm font-medium hover:text-secondary transition-colors ${textClasses}`}>
              硬件设备
            </button>
            <button 
              onClick={() => document.getElementById('contact')?.scrollIntoView({behavior: 'smooth'})}
              className={`px-5 py-2 rounded-full font-bold text-sm transition-all shadow-lg ${buttonClasses}`}
            >
              预约演示
            </button>
          </div>

          <div className="md:hidden">
            <button onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)} className={textClasses}>
              {isMobileMenuOpen ? <X /> : <Menu />}
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Menu */}
      {isMobileMenuOpen && (
        <div className="md:hidden bg-white absolute top-full left-0 w-full shadow-lg border-t border-gray-100 py-4 px-4 flex flex-col space-y-4">
